#include<bits/stdc++.h>
using namespace std;
long long n,m;
long long a[1000010],b[1000010],v[1000010];
long long l[1000010],r[1000010],tag[1000010];
int main()
{
    scanf("%lld%lld",&n,&m);
    long long len=sqrt(n);
    for(long long i=1;(i-1)*len+1<=n;i++)
    {
        l[i]=(i-1)*len+1;
        r[i]=min(i*len,n);
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        v[i]=a[i];
        b[i]=(i+len-1)/len;
    }
    for(long long i=1;i<=(n+len-1)/len;i++)
    {
        sort(v+(::l[i]),v+1+(::r[i]));
    }
    for(long long i=1;i<=m;i++)
    {
        long long l,r,c;
        char ch;
        cin>>ch;
        scanf("%lld%lld%lld",&l,&r,&c);
        if(ch=='M')
        {
            if(b[l]==b[r])
            {
                for(long long j=l;j<=r;j++)
                {
                    a[j]+=c;
                }
                for(long long j=::l[b[l]];j<=::r[b[l]];j++)
                {
                    v[j]=a[j];
                }
                sort(v+(::l[b[l]]),v+1+(::r[b[l]]));
            }
            else
            {
                for(long long j=l;j<=::r[b[l]];j++)
                {
                    a[j]+=c;
                }
                for(long long j=::l[b[r]];j<=r;j++)
                {
                    a[j]+=c;
                }
                for(long long j=::l[b[l]];j<=::r[b[l]];j++)
                {
                    v[j]=a[j];
                }
                for(long long j=::l[b[r]];j<=::r[b[r]];j++)
                {
                    v[j]=a[j];
                }
                sort(v+(::l[b[l]]),v+1+(::r[b[l]]));
                sort(v+(::l[b[r]]),v+1+(::r[b[r]]));
                for(long long j=b[l]+1;j<b[r];j++)
                {
                    tag[j]+=c;
                }
            }
        }
        else
        {
            if(b[l]==b[r])
            {
                long long sum=0;
                for(long long j=l;j<=r;j++)
                {
                    if(a[j]+tag[b[j]]>=c)
                    {
                        sum++;
                    }
                }
                printf("%lld\n",sum);
            }
            else
            {
                long long sum=0;
                for(long long j=l;j<=::r[b[l]];j++)
                {
                    if(a[j]+tag[b[j]]>=c)
                    {
                        sum++;
                    }
                }
                for(long long j=::l[b[r]];j<=r;j++)
                {
                    if(a[j]+tag[b[j]]>=c)
                    {
                        sum++;
                    }
                }
                for(long long j=b[l]+1;j<b[r];j++)
                {
                    sum+=((::r[j]-::l[j]+1)-((lower_bound(v+(::l[j]),v+(::r[j])+1,c-tag[j])-v)-(::l[j])));
                }
                printf("%lld\n",sum);
            }
        }
    }
    return 0;
}
